div.p:
ArchetypeSignature: {
label: "ArchetypeSignature (sizeof=32)"
style: {
fill: "#E8E8F0"
stroke: "#6B5B95"
stroke-width: 2
}

header: "Header" {
shape: rectangle
style: {
fill: "#6B5B95"
font-color: white
stroke-width: 0
bold: true
}
}

pre.code:
# 64-bit offsets and field labels
off0: "0x00" { style.font-size: 10; style.stroke-width: 0 }
f0: "type_ids: Vec<TypeId>" { 
  style.font: mono; style.bold: true; style.fill: "#F5F5FA" 
  tooltip: "Contains pointer, length, and capacity (24 bytes)"
}

off24: "0x18" { style.font-size: 10; style.stroke-width: 0 }
f1: "hash_cache: u64" { 
  style.font: mono; style.fill: "#F5F5FA" 
  tooltip: "Pre-computed hash of the sorted TypeId buffer"
}

div.p:
SortedVec: "Heap: [TypeId; N]" {
style: {
fill: "#DEE4E8"
stroke: "#5A6A7A"
stroke-dash: 2
}

metadata: "Invariant: ∀i, T[i] < T[i+1]" {
shape: text
style.italic: true
style.font-color: "#2C3E50"
}

buffer: {
grid-columns: 1
grid-gap: 2

pre.code:
slot0: "[0] 0x7F3A_2189 (Position)" {
  style: { fill: "#B8D4E8"; font: mono; stroke: "#5A6A7A" }
}
slot1: "[1] 0x9C2E_4517 (Velocity)" {
  style: { fill: "#C8E4D8"; font: mono; stroke: "#5A6A7A" }
}
slot2: "[2] 0xA1B2_C3D4 (Health)" {
  style: { fill: "#E8D8B8"; font: mono; stroke: "#5A6A7A" }
}

div.p:
Construction: "Construction Lifecycle" {
style: {
fill: "#F0E8F8"
stroke: "#8858A8"
}

stages: {
direction: right
input: "Unsorted\n[Vel, Pos, Vel]" { style.font: mono; shape: rectangle }
step1: "Sort\n[Pos, Vel, Vel]" { style.fill: "#F8E8FF"; shape: rectangle }
step2: "Dedup\n[Pos, Vel]" { style.fill: "#F8E8FF"; style.bold: true; shape: rectangle }
result: "ArchetypeSignature" { style.fill: "#D8C8E8"; shape: rectangle }

BinarySearch: "contains(T) → O(log n)" {
style: {
fill: "#FFE8D8"
stroke: "#D87848"
stroke-dash: 3
}

logic: {
shape: rectangle
label: "Midpoint Pivot L+(R-L)/2\nPredicate: type_id < target"
style: {
font: mono
border-radius: 20
}
}
}

HashMap: "World Archetype Index" {
style: {
fill: "#E8F0E8"
stroke: "#488848"
}

table: {
grid-columns: 3
grid-gap: 5

pre.code:
k1: "Signature([Pos, Vel])" { style.font: mono; style.fill: "#B8D8B8" }
sep1: "→" { shape: text }
v1: "ArchetypeId(3)" { style.font: mono; style.fill: "#D8E8D8" }

k2: "Signature([Pos])" { style.font: mono; style.fill: "#B8D8B8" }
sep2: "→" { shape: text }
v2: "ArchetypeId(1)" { style.font: mono; style.fill: "#D8E8D8" }

div.p:
ArchetypeSignature -> HashMap.table: "Lookup (Hash+Eq)" {
style.stroke: "#488848"
style.stroke-width: 2
}
